  return slack.chat.postMessage({ channel: '#alerts', text });
}

import crypto from 'crypto';

function verifyHubspot(req) {
  const sig = req.headers['x-hubspot-signature-v3'];
  const ts = req.headers['x-hubspot-request-timestamp'];
  if (Date.now() - Number(ts) > 5 * 60 * 1000) return false; // 5-min window
  const base = `${req.method}${req.url}${req.rawBody}${ts}`;
  const expected = crypto.createHmac('sha256', process.env.HS_SECRET).update(base).digest('base64');
  return crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expected));
}
